   136	
   137	    @Value
   138	    static class GitOrigin {
   139	        private static final Pattern[] URL_PATTERNS = {
   140	                // SSH format: git@host:path(.git)?
   141	                Pattern.compile("^git@([^:]+):(.+?)(?:\\.git)?$"),
   142	
   143	                // HTTP/HTTPS with optional username and port: http(s)://[username@]host[:port]/path(.git)?
   144	                Pattern.compile("^https?://(?:[^@]+@)?([^/:]+(?::[0-9]+)?)/(.+?)(?:\\.git)?$"),
   145	
   146	                // SSH with protocol and port: ssh://git@host[:port]/path(.git)?
   147	                Pattern.compile("^ssh://git@([^/:]+(?::[0-9]+)?)/(.+?)(?:\\.git)?$"),
   148	
   149	                // Generic protocol://[user@]host[:port]/path(.git)? - catches any other protocols
   150	                Pattern.compile("^[a-zA-Z][a-zA-Z0-9+.-]*://(?:[^@]+@)?([^/:]+(?::[0-9]+)?)/(.+?)(?:\\.git)?$")
   151	        };
   152	
   153	        String host;
   154	        String path;
   155	
   156	        static @Nullable GitOrigin parseGitUrl(String gitUrl) {
   157	            if (!isNullOrEmpty(gitUrl)) {
   158	                for (Pattern pattern : URL_PATTERNS) {
   159	                    Matcher matcher = pattern.matcher(gitUrl);
   160	                    if (matcher.matches()) {
   161	                        return new GitOrigin(matcher.group(1), matcher.group(2));
   162	                    }
   163	                }
   164	            }
   165	            return null;
   166	        }
   167	
   168	        String replaceHostAndPath(String originalUrl) {
   169	            if (isNullOrEmpty(originalUrl)) {
   170	                return originalUrl;
   171	            }
   172	
   173	            if (originalUrl.startsWith("scm:git:")) {
   174	                String actualUrl = originalUrl.substring("scm:git:".length());
   175	                return "scm:git:" + replaceHostAndPath(actualUrl);
   176	            }
   177	
   178	            // Handle git@ format (SSH)
   179	            if (originalUrl.startsWith("git@")) {
   180	                // First check if the URL already has the correct host and path
   181	                String expectedPrefix = "git@" + host + ":" + path;
   182	                if (originalUrl.startsWith(expectedPrefix)) {
   183	                    return originalUrl; // Already correct, don't modify
   184	                }
   185	
   186	                // Otherwise, replace the host and path
   187	                Matcher gitMatcher = Pattern.compile("^git@[^:]+:(.+?)$").matcher(originalUrl);
   188	                if (gitMatcher.matches()) {
   189	                    String originalFullPath = gitMatcher.group(1);
   190	                    // Check if original path ends with .git
   191	                    boolean hasGitExtension = originalFullPath.endsWith(".git");
   192	
   193	                    // Build new URL
   194	                    String newUrl = "git@" + host + ":" + path;
   195	                    if (hasGitExtension && !path.endsWith(".git")) {
   196	                        newUrl += ".git";
   197	                    }
   198	                    return newUrl;
   199	                }
   200	            }
   201	
   202	            // Handle protocol-based URLs (http, https, ssh, etc.)
   203	            Matcher protocolMatcher = Pattern.compile("^([a-zA-Z][a-zA-Z0-9+.-]*://)(?:([^@/]+)@)?([^/]+)(/[^?#]*)?(.*)?$").matcher(originalUrl);
   204	            if (protocolMatcher.find()) {
   205	                String protocol = protocolMatcher.group(1);
   206	                String user = protocolMatcher.group(2);
   207	                String originalHost = protocolMatcher.group(3);
   208	                String originalPath = protocolMatcher.group(4);
   209	                String suffix = protocolMatcher.group(5) != null ? protocolMatcher.group(5) : "";
   210	
   211	                String userPrefix = (user != null) ? user + "@" : "";
   212	
   213	                // Determine if we need to add .git extension
   214	                boolean needsGitExtension = originalPath != null && originalPath.endsWith(".git") && !path.endsWith(".git");
   215	                String newPath = "/" + path + (needsGitExtension ? ".git" : "");
   216	
   217	                // Check if the base URL already matches (to preserve suffixes)
   218	                String newBaseUrl = protocol + userPrefix + host + newPath;
   219	                if (originalUrl.startsWith(newBaseUrl)) {
   220	                    return originalUrl; // Already correct, preserve any suffix
   221	                }
   222	
   223	                return newBaseUrl + suffix;
   224	            }
   225	
   226	            // Return the original URL if no patterns matched
   227	            return originalUrl;
   228	        }
   229	    }
   230	}
